SELECT 
    (SELECT COUNT(*) FROM connections) + 
    (SELECT COUNT(*) FROM api_settings) AS total_combined_count;

SELECT provider_name, status, created_at, updated_at, last_modified_at
FROM api_providers
WHERE status = 'active';

SELECT provider_id, provider_name, description, status, version
FROM api_providers
ORDER BY provider_id;

SELECT status_before
FROM api_logs
WHERE action = 'update' AND timestamp = '2023-01-10 15:30:00';

SELECT COUNT(*) 
FROM api_logs 
WHERE provider_id = 0;

SELECT action
FROM api_logs
WHERE log_id = 0;
